import React, { useEffect, useState } from 'react';
import useFadeIn from '../../hooks/useFadeIn';
import './Education.css';

function DownloadIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true" className="edu-download-icon">
      <path
        d="M12 3v10m0 0 4-4m-4 4-4-4M5 15v3a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1v-3"
        fill="none"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="2"
      />
    </svg>
  );
}

export default function Education({ data }) {
  const ref = useFadeIn();
  const [selectedEducation, setSelectedEducation] = useState(null);

  useEffect(() => {
    if (!selectedEducation) {
      return undefined;
    }

    const previousOverflow = document.body.style.overflow;
    const handleKeyDown = (event) => {
      if (event.key === 'Escape') {
        setSelectedEducation(null);
      }
    };

    document.body.style.overflow = 'hidden';
    window.addEventListener('keydown', handleKeyDown);

    return () => {
      document.body.style.overflow = previousOverflow;
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [selectedEducation]);

  return (
    <section id="education" className="education-section">
      <div className="fade-in" ref={ref}>
        <span className="section-label"><span className="pulse" /> Education</span>
        <h2 className="section-title">Academic <span>Background</span></h2>
        <p className="section-sub">My educational journey</p>
      </div>
      <div className="edu-grid">
        {data.map((education) => {
          const hasResultPdf = Boolean(education.result_pdf_url);
          const CardTag = hasResultPdf ? 'button' : 'div';

          return (
            <CardTag
              key={education.id}
              className={`edu-card card ${hasResultPdf ? 'edu-card-clickable' : ''}`}
              onClick={hasResultPdf ? () => setSelectedEducation(education) : undefined}
              type={hasResultPdf ? 'button' : undefined}
            >
              <span className="edu-year">{education.year}</span>
              <h3 className="edu-degree">{education.degree}</h3>
              <p className="edu-inst">{education.institution}</p>
              <span className="edu-score">{education.score}</span>
              {hasResultPdf ? <span className="edu-result-pill">Tap to view semester result PDF</span> : null}
            </CardTag>
          );
        })}
      </div>
      {selectedEducation ? (
        <div className="edu-modal-backdrop" onClick={() => setSelectedEducation(null)} role="presentation">
          <div
            className="edu-modal card"
            role="dialog"
            aria-modal="true"
            aria-labelledby="education-result-title"
            onClick={(event) => event.stopPropagation()}
          >
            <button
              className="edu-modal-close"
              type="button"
              onClick={() => setSelectedEducation(null)}
              aria-label="Close result preview"
            >
              x
            </button>
            <div className="edu-modal-header">
              <span className="edu-year">{selectedEducation.year}</span>
              <h3 id="education-result-title" className="edu-modal-title">{selectedEducation.degree}</h3>
              <p className="edu-inst">{selectedEducation.institution}</p>
              <span className="edu-score">{selectedEducation.score}</span>
            </div>
            <div className="edu-modal-actions">
              <a
                href={selectedEducation.result_pdf_url}
                target="_blank"
                rel="noreferrer"
                className="btn-outline"
              >
                Open PDF
              </a>
              <a
                href={selectedEducation.result_pdf_download_url || selectedEducation.result_pdf_url}
                className="btn-primary edu-download-btn"
              >
                <DownloadIcon />
                Download PDF
              </a>
            </div>
            <div className="edu-pdf-frame-wrap">
              <iframe
                src={selectedEducation.result_pdf_url}
                title={`${selectedEducation.degree} result PDF`}
                className="edu-pdf-frame"
              />
            </div>
            {selectedEducation.result_pdf_name ? (
              <p className="edu-file-name">File: {selectedEducation.result_pdf_name}</p>
            ) : null}
          </div>
        </div>
      ) : null}
    </section>
  );
}
